const fs = require('fs');
const path = require('path');

const dir = path.join(__dirname, '../public/images/am-sequence');

if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
}

// 1x1 pixel white JPEG base64
const whitePixel = Buffer.from('', 'base64');

console.log(`Generating 181 placeholder images in ${dir}...`);

for (let i = 1; i <= 181; i++) {
    const filename = `frame-${i.toString().padStart(3, '0')}.jpg`;
    fs.writeFileSync(path.join(dir, filename), whitePixel);
}

console.log('Done!');
